12	export interface AppliedPromotion {
13	  promotion_id: string
14	  promotion_name: string
15	  promotion_type: string
16	  discount_amount: number
17	  explanation: string  // "Applied 'Buy-One-Get-One' because you have 2 workshops"
18	}
