41	  async function fetchPayment(orderId: string) {
42	    currentPayment.value = await paymentsApi.getPayment(orderId)
43	    return currentPayment.value
44	  }
45	
46	  async function pollPayment(orderId: string, onPaid: () => void) {
47	    // Poll every 3s until status = completed or max 10 min
48	    const maxAttempts = 200
49	    let attempts = 0
50	    const interval = setInterval(async () => {
51	      attempts++
52	      try {
53	        const payment = await paymentsApi.getPayment(orderId)
54	        currentPayment.value = payment
55	        if (payment.status === 'completed') {
56	          clearInterval(interval)
57	          onPaid()
58	        }
59	      } catch { /* keep polling */ }
60	      if (attempts >= maxAttempts) clearInterval(interval)
61	    }, 3000)
62	    return () => clearInterval(interval)
63	  }
64	
65	  async function submitRefund(payload: { order_id: string; amount: number; reason: string }) {
66	    return await paymentsApi.submitRefund(payload)
67	  }
68	
69	  async function approveRefund(id: string) {
70	    const updated = await paymentsApi.approveRefund(id)
71	    _replaceRefund(updated)
72	    return updated
73	  }
74	
75	  async function completeRefund(id: string) {
76	    const updated = await paymentsApi.completeRefund(id)
77	    _replaceRefund(updated)
78	    return updated
79	  }
80	
81	  async function fetchRefunds(status?: string) {
82	    refunds.value = await paymentsApi.getRefunds(status)
83	  }
84	
85	  async function triggerExport() {
86	    return await paymentsApi.triggerExport()
87	  }
88	
89	  async function fetchExports() {
90	    exports.value = await paymentsApi.getExports()
91	  }
92	
93	  function _replaceRefund(updated: Refund) {
94	    const idx = refunds.value.findIndex(r => r.id === updated.id)
95	    if (idx !== -1) refunds.value[idx] = updated
96	  }
97	
98	  return {
99	    currentPayment, refunds, exports, loading,
100	    fetchPayment, pollPayment, submitRefund,
101	    approveRefund, completeRefund, fetchRefunds, triggerExport, fetchExports,
