2	
3	// Lazy import helper to avoid circular dependency at module load time
4	let _useAuthStore: typeof import('@/stores/auth')['useAuthStore'] | null = null
5	async function getAuthStore() {
6	  if (!_useAuthStore) {
7	    const mod = await import('@/stores/auth')
8	    _useAuthStore = mod.useAuthStore
9	  }
10	  return _useAuthStore()
11	}
12	function getAuthStoreSync() {
13	  if (!_useAuthStore) return null
14	  return _useAuthStore()
15	}
16	
17	const client = axios.create({
18	  baseURL: '/',
19	  headers: { 'Content-Type': 'application/json' },
20	})
21	
22	// Attach Bearer token from auth store on every request
23	client.interceptors.request.use(async config => {
24	  const auth = await getAuthStore()
25	  if (auth.accessToken) {
26	    config.headers.Authorization = `Bearer ${auth.accessToken}`
27	  }
28	  // Let the browser set Content-Type (with boundary) for multipart uploads
29	  if (config.data instanceof FormData) {
30	    delete config.headers['Content-Type']
31	  }
32	  return config
33	})
34	
35	// Queue for requests waiting on token refresh
36	let refreshing = false
37	let waitQueue: Array<{ resolve: (token: string) => void; reject: (e: unknown) => void }> = []
38	
39	function processQueue(error: unknown, token: string | null) {
40	  waitQueue.forEach(p => error ? p.reject(error) : p.resolve(token!))
41	  waitQueue = []
42	}
43	
44	client.interceptors.response.use(
45	  res => res,
46	  async error => {
47	    const original: AxiosRequestConfig & { _retry?: boolean } = error.config
48	    const status = error.response?.status
49	
50	    if (status === 401 && !original._retry && !original.url?.includes('/api/auth/refresh') && !original.url?.includes('/api/auth/login')) {
51	      if (refreshing) {
52	        return new Promise((resolve, reject) => {
53	          waitQueue.push({
54	            resolve: token => {
55	              original.headers = { ...original.headers, Authorization: `Bearer ${token}` }
56	              resolve(client(original))
57	            },
58	            reject,
59	          })
60	        })
61	      }
62	
63	      original._retry = true
64	      refreshing = true
65	
66	      try {
67	        const auth = await getAuthStore()
68	        const newToken = await auth.refresh()
69	        processQueue(null, newToken)
70	        original.headers = { ...original.headers, Authorization: `Bearer ${newToken}` }
71	        return client(original)
72	      } catch (refreshError) {
73	        processQueue(refreshError, null)
74	        const auth = await getAuthStore()
75	        await auth.logout()
76	        window.location.href = '/login'
77	        return Promise.reject(refreshError)
78	      } finally {
79	        refreshing = false
80	      }
81	    }
82	
83	    // Normalize error shape — FastAPI validation errors return detail as an array of objects
84	    const rawDetail = error.response?.data?.detail
85	    const message = Array.isArray(rawDetail)
86	      ? rawDetail.map((e: any) => e.msg ?? String(e)).join(', ')
87	      : rawDetail ?? error.response?.data?.message ?? error.message
88	    const normalized = Object.assign(new Error(message), {
89	      statusCode: status,
90	      errors: error.response?.data?.errors,
91	    })
92	    return Promise.reject(normalized)
93	  }
94	)
95	
96	export default client
