1	import { defineStore } from 'pinia'
2	import { ref, computed } from 'vue'
3	import { authApi } from '@/api/endpoints/auth'
4	
5	export interface User {
6	  id: string
7	  username: string
8	  role: 'admin' | 'instructor' | 'learner' | 'finance' | 'dataops'
9	  tz: string
10	}
11	
12	export const useAuthStore = defineStore('auth', () => {
13	  const user = ref<User | null>(null)
14	  const accessToken = ref<string | null>(null)
15	  const loading = ref(false)
16	  const error = ref<string | null>(null)
17	
18	  const isAuthenticated = computed(() => !!accessToken.value)
19	  const role = computed(() => user.value?.role)
20	  const isAdmin = computed(() => role.value === 'admin')
21	  const isInstructor = computed(() => role.value === 'instructor')
22	  const isLearner = computed(() => role.value === 'learner')
23	  const isFinance = computed(() => role.value === 'finance')
24	  const isDataOps = computed(() => role.value === 'dataops')
25	
26	  function decodeJwt(token: string): { sub: string; role: User['role']; exp: number } {
27	    const payload = token.split('.')[1]
28	    return JSON.parse(atob(payload))
29	  }
30	
31	  async function login(username: string, password: string) {
32	    loading.value = true
33	    error.value = null
34	    try {
35	      const data = await authApi.login(username, password)
36	      accessToken.value = data.access_token
37	      const claims = decodeJwt(data.access_token)
38	      user.value = {
39	        id: claims.sub,
40	        username,
41	        role: claims.role,
42	        tz: Intl.DateTimeFormat().resolvedOptions().timeZone,
43	      }
44	      localStorage.setItem('refresh_token', data.refresh_token)
45	      localStorage.setItem('auth_user', JSON.stringify(user.value))
46	    } finally {
47	      loading.value = false
48	    }
49	  }
50	
51	  async function refresh() {
52	    const rt = localStorage.getItem('refresh_token')
53	    if (!rt) throw new Error('No refresh token')
54	    const data = await authApi.refresh(rt)
55	    accessToken.value = data.access_token
56	    localStorage.setItem('refresh_token', data.refresh_token)
57	    // Restore user info, updating role from the fresh JWT
58	    const claims = decodeJwt(data.access_token)
59	    const stored = localStorage.getItem('auth_user')
60	    if (stored) {
61	      user.value = { ...JSON.parse(stored), role: claims.role }
62	    } else {
63	      user.value = { id: claims.sub, username: claims.sub, role: claims.role, tz: Intl.DateTimeFormat().resolvedOptions().timeZone }
64	    }
65	    return data.access_token
66	  }
67	
68	  async function logout() {
69	    try { await authApi.logout() } catch { /* ignore */ }
70	    accessToken.value = null
71	    user.value = null
72	    localStorage.removeItem('refresh_token')
73	    localStorage.removeItem('auth_user')
74	  }
75	
76	  async function changePassword(currentPassword: string, newPassword: string) {
77	    await authApi.changePassword(currentPassword, newPassword)
78	  }
79	
80	  // Restore session on app load from refresh token
81	  async function restoreSession() {
82	    const rt = localStorage.getItem('refresh_token')
83	    if (!rt) return
84	    try {
85	      await refresh()
86	    } catch {
87	      localStorage.removeItem('refresh_token')
88	    }
89	  }
90	
91	  return {
92	    user, accessToken, loading, error,
93	    isAuthenticated, role, isAdmin, isInstructor, isLearner, isFinance, isDataOps,
94	    login, refresh, logout, changePassword, restoreSession,
95	  }
96	})
97	
